const fileInput=document.getElementById("file-upload"),previewImage=document.getElementById("preview-image"),uploaderForm=document.getElementById("uploader-form");let imageList,imageElements=[],currentImage=0;function displayImage(e){"use strict";if(e.files&&e.files[0]){currentImage=0,imageElements=[],imageList=e.files;let t=[];for(let e of imageList){let l=new Promise(t=>{let l=new FileReader;l.readAsDataURL(e),l.onload=()=>t(l.result)});t.push(l)}Promise.all(t).then(e=>{for(let t of e){let e=document.createElement("img");e.className="preview-image",e.src=t,imageElements.push(e)}changeImage(imageElements[currentImage])})}}function changeImage(e){previewImage.replaceChildren(e)}function hideOtherSlides(e){for(let t of document.getElementsByClassName("uploader-panel"))t.id!=e?t.style.display="none":t.style.display="flex"}function slide1(){document.getElementById("uploader-title-text").innerText="Select Files",document.getElementById("left-button").style.visibility="hidden",document.getElementById("right-button").style.visibility="visible",document.getElementById("right-button").onclick=()=>{slide2()},document.getElementById("upload-button").style.display="none",document.getElementById("right-button").style.display="block",hideOtherSlides("first-panel")}function slide2(){document.getElementById("uploader-title-text").innerText="Select Tags",document.getElementById("left-button").style.visibility="visible",document.getElementById("left-button").onclick=()=>{slide1()},document.getElementById("right-button").style.visibility="visible",document.getElementById("right-button").onclick=()=>{slide3()},document.getElementById("right-button").style.display="block",document.getElementById("upload-button").style.display="none",hideOtherSlides("second-panel")}function slide3(){document.getElementById("uploader-title-text").innerText="Extra Information",document.getElementById("left-button").style.visibility="visible",document.getElementById("left-button").onclick=()=>{slide2()},document.getElementById("right-button").style.display="none",document.getElementById("upload-button").style.display="block",hideOtherSlides("third-panel")}function invokeForm(){0===fileInput.files.length?(slide1(),alert("Please select some files!")):uploaderForm.submit()}document.getElementById("left-button-image").onclick=()=>{currentImage-=1,changeImage(imageElements[currentImage])},document.getElementById("right-button-image").onclick=()=>{currentImage+=1,changeImage(imageElements[currentImage])};